package com.cognizant.gateway.filter;import org.slf4j.*;import org.springframework.cloud.gateway.filter.*;import org.springframework.core.Ordered;import org.springframework.stereotype.Component;import org.springframework.web.server.ServerWebExchange;import reactor.core.publisher.Mono;@Component public class LogFilter implements GlobalFilter,Ordered{private static final Logger log=LoggerFactory.getLogger(LogFilter.class);public Mono<Void> filter(ServerWebExchange e,GatewayFilterChain c){log.info("Incoming {} {}",e.getRequest().getMethod(),e.getRequest().getURI());return c.filter(e);}public int getOrder(){return -1;}}